"use client";
import { MorphingModal } from "@/components/ui/morphing-modal";
import { useState } from "react";

export default function ConfirmDelete() {
  const [open, setOpen] = useState(false);

  return (
    <div className="flex items-center justify-center p-20">
      <button
        onClick={() => setOpen(true)}
        className="px-4 py-2 bg-red-500/10 text-red-400 border border-red-500/20 rounded-lg text-sm"
      >
        Delete project
      </button>

      <MorphingModal isOpen={open} onClose={() => setOpen(false)}>
        <div className="p-6 space-y-4 max-w-sm">
          <h2 className="text-lg font-semibold text-white">Are you sure?</h2>
          <p className="text-sm text-neutral-400">
            This will permanently delete the project and all its data. This action cannot be undone.
          </p>
          <div className="flex gap-3 pt-2">
            <button
              onClick={() => setOpen(false)}
              className="flex-1 py-2 rounded-lg border border-neutral-700 text-neutral-300 text-sm"
            >
              Cancel
            </button>
            <button className="flex-1 py-2 rounded-lg bg-red-600 text-white text-sm font-medium">Delete</button>
          </div>
        </div>
      </MorphingModal>
    </div>
  );
}

