"use client";
import { MorphingModal } from "@/components/ui/morphing-modal";
import { useState } from "react";
import { motion, AnimatePresence } from "motion/react";

const steps = ["Welcome", "Choose plan", "You're ready"];

export default function OnboardingModalDemo() {
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState(0);

  return (
    <div className="flex items-center justify-center p-20">
      <button
        onClick={() => { setStep(0); setOpen(true); }}
        className="px-6 py-3 bg-purple-600 text-white rounded-xl font-medium"
      >
        Start onboarding
      </button>

      <MorphingModal isOpen={open} onClose={() => setOpen(false)}>
        <div className="p-8 w-full max-w-md space-y-6">
          <div className="flex gap-1.5">
            {steps.map((_, i) => (
              <div key={i} className={`h-1 flex-1 rounded-full transition-colors ${i <= step ? "bg-purple-500" : "bg-neutral-700"}`} />
            ))}
          </div>
          <AnimatePresence mode="wait">
            <motion.div key={step} initial={{ opacity: 0, x: 12 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -12 }} className="space-y-2">
              <h2 className="text-xl font-bold text-white">{steps[step]}</h2>
              <p className="text-sm text-neutral-400">Step {step + 1} of {steps.length}</p>
            </motion.div>
          </AnimatePresence>
          <button
            onClick={() => step < steps.length - 1 ? setStep(s => s + 1) : setOpen(false)}
            className="w-full py-2.5 bg-purple-600 text-white rounded-xl font-medium"
          >
            {step < steps.length - 1 ? "Continue" : "Finish"}
          </button>
        </div>
      </MorphingModal>
    </div>
  );
}
